pub fn normalize_title(input: &str) -> String {
    fn cap_piece(piece: &str) -> String {
        let mut chars = piece.chars();
        match chars.next() {
            Some(first) => {
                let mut out = String::new();
                out.push(first.to_ascii_uppercase());
                out.push_str(&chars.as_str().to_ascii_lowercase());
                out
            }
            None => String::new(),
        }
    }

    input
        .split_whitespace()
        .map(|word| {
            word.split('-')
                .map(cap_piece)
