            if has_alnum && !prev_space {
                out.push(' ');
                prev_space = true;
            }
            prev_hyphen = false;
        } else if c == '-' {
            if has_alnum && !prev_space && !prev_hyphen {
                out.push('-');
                prev_hyphen = true;
                prev_space = false;
            }
        }
    }

    while out.ends_with([' ', '-']) {
        out.pop();
    }

    out
}

