    #[test]
    fn trims_outer_separators() {
        assert_eq!(normalize_label("  --Alpha_beta--  "), "alpha-beta");
    }

    #[test]
    fn removes_non_ascii_punctuation_without_joining_words() {
        assert_eq!(normalize_label("Rust!Lang...2021"), "rustlang2021");
    }

    #[test]
    fn returns_default_when_nothing_remains() {
        assert_eq!(normalize_label("___ --- !!!"), "n-a");
    }
}

